# N_c: Number of cooperators observed in the previous round
# t: Current round number
# r: Total rounds
# n: Total players

def decide_action(S_prev, N_c, t, r, n):
    # Edge case: First round
    if t == 1:
        return 'C'

    # Edge case: Last round
    if t == r:
        if S_prev >= (capacity / 2):
            return 'C'
