    if t == 1:
        return 'C'

    # Panic Preservation: If stock is dangerously low, prioritize resource survival
    if S_t <= (capacity / (2 * n)):
        return 'C'

    # Last Round: Defect to maximize score, unless stock is near depletion
    if t == r:
        if S_t > (capacity / 2):
            return 'D'
        else:
            return 'C'

    # Reciprocal Logic:
    # Calculate cooperation rate of others
    p_coop = last_round_opponents_cooperated / (n - 1)
    
