    if current_stock < (0.25 * capacity):
        return 'C'
    
    # Edge case: Last round logic
    if round_number == r:
        if current_stock >= (0.25 * capacity):
            return 'D'
        return 'C'

    # Round 1 initialization
    if round_number == 1:
        return 'C'

    # Tit-for-tat logic
